import{_ as t,o as a,c as s,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-028 — Outer planets + dwarf planets in /plan: scope and scaling","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-028.md","filePath":"adr/ADR-028.md"}'),n={name:"adr/ADR-028.md"};function o(r,e,l,d,c,p){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="adr-028-—-outer-planets-dwarf-planets-in-plan-scope-and-scaling" tabindex="-1">ADR-028 — Outer planets + dwarf planets in /plan: scope and scaling <a class="header-anchor" href="#adr-028-—-outer-planets-dwarf-planets-in-plan-scope-and-scaling" aria-label="Permalink to &quot;ADR-028 — Outer planets + dwarf planets in /plan: scope and scaling&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-02 Closes · RFC-008 (Outer planets + dwarf planets) TA anchor · §components/lambert-worker · §components/plan-screen Related ADRs · ADR-008 (Lambert worker), ADR-022 (Lambert protocol), ADR-023 (mobile magnifier), ADR-026 (multi-destination v0.1.6 / 5 destinations)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>ADR-026 shipped 5 destinations in v0.1.6: Mercury, Venus, Mars, Jupiter, Saturn. Three outer planets (Uranus, Neptune) and Pluto plus all dwarf planets were explicitly deferred to v0.3.0. RFC-008 raised three open questions: Y-axis scaling for multi-decade transfers, gravity-assist modelling, and dwarf-planet inclusion. This ADR locks every variable so the v0.3.0 implementation has a single contract.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="destination-scope-rfc-§dwarf-planets-—-option-dw-b-refined" tabindex="-1">Destination scope (RFC §dwarf-planets — Option DW-B refined) <a class="header-anchor" href="#destination-scope-rfc-§dwarf-planets-—-option-dw-b-refined" aria-label="Permalink to &quot;Destination scope (RFC §dwarf-planets — Option DW-B refined)&quot;">​</a></h3><p><strong>Four new destinations ship in v0.3.0:</strong> Uranus, Neptune, Pluto, Ceres. Total destination count rises from 5 → 9.</p><table tabindex="0"><thead><tr><th>id</th><th style="text-align:right;">Hohmann transit</th><th style="text-align:right;">tof_range_days</th><th>mission_types</th><th>Notes</th></tr></thead><tbody><tr><td>uranus</td><td style="text-align:right;">~16.0 yr</td><td style="text-align:right;">[3000, 6500] (8.2–17.8 yr)</td><td>FLYBY</td><td>Voyager 2 only flown</td></tr><tr><td>neptune</td><td style="text-align:right;">~30.6 yr</td><td style="text-align:right;">[10000, 20000] (27–55 yr)</td><td>FLYBY</td><td>Voyager 2 only flown</td></tr><tr><td>pluto</td><td style="text-align:right;">~45.5 yr</td><td style="text-align:right;">[12000, 22000] (33–60 yr)</td><td>FLYBY</td><td>New Horizons only flown</td></tr><tr><td>ceres</td><td style="text-align:right;">~3.4 yr</td><td style="text-align:right;">[800, 1800] (2.2–4.9 yr)</td><td>LANDING, FLYBY</td><td>Dawn (orbit insertion)</td></tr></tbody></table><p>LANDING availability for Ceres mirrors Mars/Venus/Mercury (per ADR-026&#39;s possibility-driven rule). All other v0.3.0 entries are FLYBY-only — surface landings on gas giants / ice giants / Pluto are not defined manoeuvres at this fidelity level.</p><p><strong>Eris, Makemake, Haumea</strong> explicitly deferred. Their multi-century orbits don&#39;t read on the 112×100 grid and they have no flown missions — adding them would be educational noise.</p><h3 id="y-axis-scaling-rfc-§y-axis-—-option-ya-a" tabindex="-1">Y-axis scaling (RFC §y-axis — Option YA-A) <a class="header-anchor" href="#y-axis-scaling-rfc-§y-axis-—-option-ya-a" aria-label="Permalink to &quot;Y-axis scaling (RFC §y-axis — Option YA-A)&quot;">​</a></h3><p>Per-destination tof range expressed in <strong>years on the axis label</strong> when <code>tof_range_days[1] &gt; 730</code> (the v0.1.6 threshold). Year ticks are integer-valued (<code>5y</code>, <code>10y</code>, <code>15y</code> ...). Mars stays in days; outer planets all flip to years; Ceres at ~4 years also flips to year-tick mode.</p><p>The educational moment the v0.1.6 work landed for Saturn (&quot;12-year cycle&quot;) extends naturally — Neptune now visibly takes &quot;a generation&quot; while a Mars launch window arrives every 26 months.</p><p><strong>Logarithmic axis (Option YA-B) rejected</strong> — the porkchop&#39;s &quot;cheapest cell&quot; insight depends on linear time; log scaling would compress the Hohmann minimum into illegibility.</p><h3 id="gravity-assist-scope-rfc-§gravity-assist-—-option-ga-a" tabindex="-1">Gravity-assist scope (RFC §gravity-assist — Option GA-A) <a class="header-anchor" href="#gravity-assist-scope-rfc-§gravity-assist-—-option-ga-a" aria-label="Permalink to &quot;Gravity-assist scope (RFC §gravity-assist — Option GA-A)&quot;">​</a></h3><p><strong>Direct-Hohmann trajectories only.</strong> The pre-computed grids show what a direct launch costs; real outer-planet missions use planetary gravity assists which are out of scope.</p><p>Each outer-planet panel surfaces a one-line caveat banner (mirroring the v0.1.7 sparse-data caveat pattern):</p><blockquote><p><em>Direct trajectory shown. Real outer-planet missions use planetary gravity assists — see Voyager 2, Galileo, Cassini, New Horizons in /missions for actual flight paths.</em></p></blockquote><p><strong>Option GA-C</strong> (Voyager/Galileo reference overlays) deferred to a possible v0.4. Its educational power is real but engineering scope (multi-leg Lambert with patched-conic approximations) belongs in its own RFC.</p><h3 id="schema-additions" tabindex="-1">Schema additions <a class="header-anchor" href="#schema-additions" aria-label="Permalink to &quot;Schema additions&quot;">​</a></h3><p><code>DestinationConstants</code> in <code>src/lib/lambert-grid.constants.ts</code> gains an optional <code>e</code> field (eccentricity). Used only by Pluto where the circular-orbit approximation breaks; defaults to 0 for all others.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DestinationConstants</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> DestinationId</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// semi-major axis, AU</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  a0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// mean longitude at epoch, rad</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  meanMotionRadPerDay</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// eccentricity (default 0 — circular approx)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>DestinationId</code> enum extends to include the 4 new ids.</p><h3 id="lambert-convergence-policy-rfc-oq-2" tabindex="-1">Lambert convergence policy (RFC OQ #2) <a class="header-anchor" href="#lambert-convergence-policy-rfc-oq-2" aria-label="Permalink to &quot;Lambert convergence policy (RFC OQ #2)&quot;">​</a></h3><p>For multi-decade transfers, Lambert&#39;s iterative solution can fail to converge or produce negative ∆v values. The solver already returns <code>DV_FAILED</code> for such cells; outer-planet grids may have higher failure rates than inner-planet grids.</p><p><code>scripts/precompute-porkchops.ts</code> records the per-destination convergence statistic in the JSON&#39;s <code>credit</code> field:</p><blockquote><p><code>Computed at build time via Lambert solver. Uranus: 84% convergence. Failed cells render as DV_FAILED.</code></p></blockquote><p>UI behaviour: failed cells render as the existing dark-grey background; magnifier shows &quot;—&quot; for non-convergent cells.</p><h3 id="fly-arc-geometry-for-multi-year-trajectories" tabindex="-1"><code>/fly</code> arc geometry for multi-year trajectories <a class="header-anchor" href="#fly-arc-geometry-for-multi-year-trajectories" aria-label="Permalink to &quot;\`/fly\` arc geometry for multi-year trajectories&quot;">​</a></h3><p>The v0.1.6-introduced single-ellipse <code>outboundArc()</code> already handles outer destinations (positive eccentricity for outer, negative for inner). For Pluto (e=0.249), pass the eccentricity through so the visible arc reads as the truly-elongated trajectory rather than a misleading circular curve.</p><p>Camera framing per <code>cameraDistanceFor()</code> from v0.1.10: Neptune at ~30 AU = ~2400 scene units; Pluto at ~40 AU = ~3200 units. Adjust the camR clamp upper bound from 900 → 4000.</p><h3 id="mission-catalogue-additions-in-scope" tabindex="-1">Mission catalogue additions (in scope) <a class="header-anchor" href="#mission-catalogue-additions-in-scope" aria-label="Permalink to &quot;Mission catalogue additions (in scope)&quot;">​</a></h3><p>v0.3.0 also adds the 4 missions that justify these destinations:</p><ul><li><strong>Voyager 2</strong> (1977) — Jupiter / Saturn / Uranus / Neptune flybys. Multi-destination mission; <code>dest</code> field needs special handling (or just list it as <code>dest: NEPTUNE</code> since that&#39;s the final flyby) — TBD in implementation.</li><li><strong>Galileo</strong> (1989) — Jupiter orbiter. Could be backfilled to v0.1.6&#39;s Jupiter destination but landed in v0.3.0 for catalogue coherence.</li><li><strong>New Horizons</strong> (2006) — Pluto flyby + Kuiper Belt extended mission. Real gravity-assist trajectory documented; in <code>flight_data_quality: measured</code> since data is public.</li><li><strong>Dawn</strong> (2007) — Vesta + Ceres orbiter. Two-target mission; list <code>dest: CERES</code> as the final destination.</li></ul><p>Total mission catalogue grows from 28 → 32.</p><h3 id="url-contract-extends-adr-026" tabindex="-1">URL contract (extends ADR-026) <a class="header-anchor" href="#url-contract-extends-adr-026" aria-label="Permalink to &quot;URL contract (extends ADR-026)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plan?dest={mercury|venus|mars|jupiter|saturn|uranus|neptune|pluto|ceres}&amp;type={LANDING|FLYBY}</span></span></code></pre></div><ul><li>Default still <code>dest=mars</code> (no regression).</li><li>Invalid <code>?dest=eris</code> (or any deferred dwarf) coerces to <code>mars</code> with a one-time console warning, not a UI error.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The decision cluster around three principles already locked elsewhere:</p><ul><li><strong>PRD-002</strong>: &quot;intuitive before explanation&quot; — drives the linear (not log) Y-axis and the direct-trajectory-only choice. A user reading the Neptune porkchop should think &quot;this takes a generation,&quot; not &quot;I need to learn what a log axis means.&quot;</li><li><strong>PA §promises — fail honestly</strong> — drives the gravity-assist caveat banner. We don&#39;t pretend the porkchop shows what real missions do; we tell the user.</li><li><strong>ADR-016 (build-time assets)</strong> — drives the pre-computed grid pattern; same as v0.1.6.</li></ul><p>The &quot;drop dwarfs&quot; rule (DW-B refined) is selective: Pluto + Ceres earn inclusion through New Horizons + Dawn. The remaining dwarfs (Eris/Makemake/Haumea) lack flown missions and have orbits that don&#39;t read at our format.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Option DW-C — all four dwarfs</strong> rejected because Eris (a=67 AU, e=0.43) doesn&#39;t compute a sensible Hohmann porkchop — its perihelion is at 38 AU and aphelion at 97 AU, so transfer parameters depend heavily on which orbital phase you target. Adding it would be visual noise.</li><li><strong>Option YA-B — log-scale Y-axis</strong> rejected because porkchops teach &quot;this is the cheapest <em>date</em>,&quot; and log-scale obscures the date axis for the user.</li><li><strong>Option GA-B — two grids per outer destination (direct + Jupiter-assisted)</strong> rejected as scope-doubling for marginal teaching gain. The caveat banner + the v0.4 reference-trajectory option captures the teaching moment cleanly.</li><li><strong>Skip Pluto entirely</strong> rejected — New Horizons is the most-Googled outer-system mission of the last decade; its absence would be glaring.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li><code>/plan</code> covers 9 of the major solar-system destinations (8 planets + Ceres). Pluto&#39;s inclusion as a dwarf opens the door for an educational thread on the IAU 2006 redefinition.</li><li>Lambert worker&#39;s parameterisation extends naturally — same per-destination JSON contract as v0.1.6.</li><li>Y-axis scaling continues the pattern from v0.1.6 (Saturn already in years).</li><li>4 new missions deepen the catalogue: Voyager 2, Galileo, New Horizons, Dawn — landmark missions that v0.1.x oddly omitted.</li></ul><p><strong>Negative:</strong></p><ul><li>~880 KB of new pre-computed grid data (4 × ~220 KB; outer-planet grids are slightly larger because Lambert convergence stats compress less). Total now ~1.4 MB for the 9-destination grid set. Within budget but worth noting.</li><li>Multi-year transfer windows + Lambert convergence at extreme distances need careful testing. The <code>DV_FAILED</code> rate may be 15–20% for Neptune/Pluto vs &lt;5% for inner planets. Document this honestly.</li><li><code>/fly</code> camera-distance upper bound lifts from 900 → 4000. Some legacy mission entries may need camR re-tuning.</li><li>The gravity-assist caveat banner may frustrate STEM students looking for &quot;the real trajectory.&quot; The follow-up RFC for reference overlays (Option GA-C) is already framed.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>Implementation lives in v0.3.0 milestone (issue #27 tracker). Slice plan:</p><ul><li><strong>3.0a-1</strong> — Schema + types. Extend <code>DestinationConstants</code> with optional <code>e</code>. New <code>DestinationId</code> enum entries. Update <code>lambert-grid.constants.ts</code> to include all 9 destinations.</li><li><strong>3.0a-2</strong> — Pre-computed grids. <code>scripts/precompute-porkchops.ts</code> runs over the 4 new destinations. Verify Lambert convergence stats; record per-destination in JSON <code>credit</code> field.</li><li><strong>3.0a-3</strong> — <code>/plan</code> UI. Destination dropdown extends to 9. LANDING/FLYBY toggle correctly disabled for outer planets + Pluto. Y-axis year ticks at 5y intervals.</li><li><strong>3.0a-4</strong> — <code>/fly</code> arc geometry. Pass eccentricity through <code>outboundArc()</code> for Pluto. Adjust <code>cameraDistanceFor()</code> upper bound. Caveat banner under the FLY button.</li><li><strong>3.0a-5</strong> — Mission catalogue. Add Voyager 2, Galileo, New Horizons, Dawn with measured flight data. 28 → 32 missions. Each gets the standard mission JSON shape per ADR-020 + ADR-027.</li><li><strong>3.0a-6</strong> — Tests + docs roll-up. Extend e2e to cover Neptune porkchop convergence, Pluto camera framing, Voyager 2 mission load. Tag v0.3.0.</li></ul><p>The v0.4 deferred work (gravity-assist reference overlays) is tracked separately; this ADR doesn&#39;t open that thread.</p>`,53)])])}const g=t(n,[["render",o]]);export{u as __pageData,g as default};
